// ═══════════════════════════════════════════════════════════
// CLOUD SYNC HOOK
// Automatically backups local data to Firestore when online
// ═══════════════════════════════════════════════════════════

import { useEffect, useRef } from 'react';
import { useAuthStore } from '@/stores/auth-store';
import { useClaimStore } from '@/stores/claim-store';
import { pushClaimToCloud, pullClaimsFromCloud, syncAllLocalToCloud } from '@/lib/firebase/sync';

export function useCloudSync() {
  const { user, isAuthenticated } = useAuthStore();
  const { currentClaim, isDirty, markClean } = useClaimStore();
  const isSyncingFullRef = useRef(false);

  // 1. Initial Sync on Login (Pull remote data, migrate local data)
  useEffect(() => {
    if (isAuthenticated && user && !isSyncingFullRef.current) {
      isSyncingFullRef.current = true;
      (async () => {
        try {
          console.log('[useCloudSync] Initial full sync started...');
          // Migrate any existing local data first
          await syncAllLocalToCloud(user.uid);
          // Pull any newer data from cloud
          await pullClaimsFromCloud(user.uid);
          console.log('[useCloudSync] Initial full sync complete.');
        } catch (err) {
          console.error('[useCloudSync] Initial sync failed:', err);
        }
      })();
    } else if (!isAuthenticated) {
      isSyncingFullRef.current = false;
    }
  }, [isAuthenticated, user]);

  // 2. Continuous Sync (Triggered when marked 'clean' from local AutoSave)
  useEffect(() => {
    // If a claim exists, isn't dirty (already saved to IndexedDB), and user is logged in
    if (isAuthenticated && user && currentClaim && !isDirty) {
      (async () => {
        try {
          // Push the latest clean state from IndexedDB to the cloud
          await pushClaimToCloud(user.uid, currentClaim);
          console.log(`[useCloudSync] Pushed claim ${currentClaim.id} to Firestore.`);
        } catch (err) {
          console.error('[useCloudSync] Cloud push failed (offline?):', err);
        }
      })();
    }
  }, [isAuthenticated, user, currentClaim, isDirty]);
}
